static NSDictionary *WBMergeBenefitUsage(NSDictionary *existing, NSArray *features) {
    NSMutableSet *allowed = [NSMutableSet set];
    for (id obj in features) {
        if ([obj respondsToSelector:@selector(bit)]) {
            NSNumber *bitNum = [obj valueForKey:@"bit"];
            NSInteger bit = [bitNum integerValue];
            if (bit != 0) {
                [allowed addObject:[NSString stringWithFormat:@"%ld", (long)bit]];
            }
        }
    }
    NSMutableDictionary *result = [NSMutableDictionary dictionaryWithCapacity:allowed.count];
    [existing enumerateKeysAndObjectsUsingBlock:^(id key, id obj, BOOL *stop) {
        if ([allowed containsObject:key]) {
            NSInteger integerValue = 0;
            if ([obj isKindOfClass:NSNumber.class]) {
                integerValue = [obj integerValue];
            } else {
                integerValue = [[obj description] integerValue];
            }
            if (integerValue < 0) integerValue = 0;
            result[key] = @(integerValue);
        }
    }];
    for (NSString *key in allowed) {
        if (!result[key]) result[key] = @(0);
    }
    return result;
}


