@property(nonatomic, strong) Reachability *internetReachability;// 网络是否连接

@property(nonatomic, readonly) dispatch_queue_t queue;

@property(nonatomic, readwrite) TokenRefreshStatus tokenRefreshStatus;

@property(nonatomic, readwrite) CFAbsoluteTime lastRequestTime;

