@implementation WBAppManager




#pragma mark singleton

+ (void)load {
    NSLog(@"load WBAppManager sharedManager");
    [WBAppManager sharedManager];
}

+ (instancetype)sharedManager {
    static WBAppManager *defaultManager = nil;
    static dispatch_once_t onceToken;
    dispatch_once(&onceToken,^{
        defaultManager = [[self alloc] init];
    });

    return defaultManager;
}

- (instancetype)init {
    self = [super init];
    if (self) {
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppFinishLaunching) name:UIApplicationDidFinishLaunchingNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppEnterBackground) name:UIApplicationDidEnterBackgroundNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppEnterForeground) name:UIApplicationWillEnterForegroundNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppBecomeActive) name:UIApplicationDidBecomeActiveNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppResignActive) name:UIApplicationWillResignActiveNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(onAppWillTerminate) name:UIApplicationWillTerminateNotification object:nil];
        [NSNotificationCenter.defaultCenter addObserver:self selector:@selector(handleSceneDidDisconnect:) name:UISceneDidDisconnectNotification
            object:nil];

        _queue = dispatch_queue_create("__amqueue", NULL);
        _tokenRefreshStatus = tokenAwaitRefresh;
        _lastRequestTime = 0;
        _requestInterval = 0.8;
        _rootvc = [WBLaunchViewController class];
        _appBundlePath = [NSBundle mainBundle].bundlePath;
        _convertToVappVC = FALSE;
        _isBRootViewController = TRUE;
    }
    return self;
}

- (void)dealloc {
    NSLog(@"dealloc WBAppManager");
    [[NSNotificationCenter defaultCenter] removeObserver:self];
    [[UIScreen mainScreen] removeObserver:self forKeyPath:@"captured"];
    if (self.observingClazz) {
        [self removeObserver:self forKeyPath:@"clazz"];
        self.observingClazz = NO;
    }
}

#pragma mark lifecycle observer

- (void)onAppFinishLaunching {
    // Guest App launching msg
    static dispatch_once_t onceToken;// 使用 static 的 dispatch_once_t 来保证代码块只执行一次，无论应用程序启动多少次。
    dispatch_once(&onceToken, ^{
        NSLog(@"launching");
        LogApplicationState;// 调用 LogApplicationState 宏，打印应用程序当前的状态信息。
        [WBEventManager onAppFinishLaunching];// 通知事件管理器应用程序已完成启动。
        [[WBStorageManager sharedManager] fileSystemVersionCheck];// 检查并应用文件系统的版本更新。



        // if engine resource hash is set, it indicates that the user has seen face B
        // in such cases, remove the force face A restrictions
        if (IsInReview() == 0 &&
            (WBSettingManager.sharedManager.EngresHash != nil ||
            SecondsElapsedSincePack() > ABBridge_GetForceATimeInSeconds())) {
            [self observeNetworkStatus];// 开始监听网络状态。
            [self observeScreenShotAndScreenRecordEvent];// 开始监听截屏和录屏事件。
        } else {
            // 如果用户尚未看到过界面 B，则延迟0.1秒后在主队列上设置应用程序的根视图控制器为界面 A。
            // SHOW FACE A
            dispatch_after(dispatch_time_delay(0.1), dispatch_get_main_queue(), ^{
                // 获取界面 A 的视图控制器类，成功获取后就将其设置为根视图控制器
                Class clazz = ABBridge_GetARootViewControllerClass();
                if (clazz) {
                    [self setRootViewController:clazz];
                    self.isBRootViewController = FALSE;
                }
            });
        }
    });
}




/// 应用进入后台时通知各业务模块，同时由 WBEventManager 记录 heartbeat 相关的后台快照。
- (void)onAppEnterBackground {
    NSLog(@"background");
    self.enterBackgroundTime = CFAbsoluteTimeGetCurrent();// 处理虚拟应用的自动锁定逻辑，记录当前时间为进入后台的时间。这个时间戳可能用于自动锁定功能，以确定应用程序在后台闲置多久后自动锁定。
    // 旧逻辑：
    // [WBEventManager recordAppEnterBackgroundTime:self.enterBackgroundTime];
    [WBEventManager onAppEnterBackground]; // 通知事件管理器应用程序已进入后台，可能触发相关的事件处理。
    [WBKeeperManager.sharedManager onAppEnterBackground];// 通知数据保持管理器应用程序已进入后台，可能进行数据的保存或其他操作。
    [WBVAppDownloadManager.sharedManager onEnterBackground];// 通知虚拟应用下载管理器应用程序已进入后台，可能需要暂停下载任务。
    [WBVAppResDownloadManager.sharedManager onEnterBackground];// 通知虚拟应用资源下载管理器应用程序已进入后台，可能涉及资源下载的逻辑处理。
    [WBGroMoreAdManager.sharedManager onEnterBackground];// 通知广告管理器应用程序已进入后台，可能需要关闭插屏广告。
}

/// 应用回到前台时先补算后台挂起时长，再继续原有前台事件和自动锁逻辑。
- (void)onAppEnterForeground {
    NSLog(@"foreground");
    LogApplicationState;// 记录应用程序当前的状态信息。
    // 先补算后台挂起区间，避免 heartbeat 的 a/v 在回前台后仍然停留在旧值。
    [WBEventManager syncUsageOnAppEnterForeground];
    if (!self.convertToVappVC) {
        [WBEventManager onAppEnterForeground];// 通知事件管理器应用程序已进入前台，可能触发相关的事件处理。
    } else {
        self.convertToVappVC = FALSE;
    }
    [WBKeeperManager.sharedManager onAppEnterForeground];// 通知数据保持管理器应用程序已进入前台，可能进行数据的恢复或其他操作。
    WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;// 获取当前正在运行的虚拟应用（VApp）模型。

    // 处理虚拟应用的自动锁定逻辑。
    // handle vapp autolock
    if (!self.enterBackgroundTime) return; // Never enter background.// 如果从未进入后台，则不执行后续操作。
    if (!runningVApp || ![WBSettingManager sharedManager].IsVIP) return;
    // 如果没有设置自动锁定时长或当前时间与进入后台的时间差小于自动锁定时长，则不执行后续操作。
    if (!runningVApp.autoLockDuration || CFAbsoluteTimeGetCurrent() - self.enterBackgroundTime < runningVApp.autoLockDuration) return;
    UIViewController *rootVC = [WBAppManager getUIApplicationRootViewController];   // 获取当前应用程序的根视图控制器。
    WBPasswordViewController *passwdVC = [[WBPasswordViewController alloc] init];// 初始化密码输入视图控制器。
    passwdVC.vapp = runningVApp;
    passwdVC.bioEnable = true;// 启用生物识别功能。
    passwdVC.type = WBPasswordViewControllerTypeEntry;// 设置密码输入类型为进入。
    __weak UIViewController *weakPasswdVC = passwdVC;// 使用弱引用避免内存强引用循环。
    // 设置密码输入成功的处理块，用于解散密码输入视图控制器。
    passwdVC.successBlock = ^{
        [weakPasswdVC dismissViewControllerAnimated:true completion:nil];
        self.presentingPasswdVC = nil;// 清除强引用。
    };
    // 将密码输入视图控制器封装进导航控制器，并设置全屏展示样式。
    UINavigationController *wrapVC = [[UINavigationController alloc] initWithRootViewController:passwdVC];
    wrapVC.modalPresentationStyle = UIModalPresentationFullScreen;
    // 根据是否有其他视图控制器正在展示，决定在哪个视图控制器上展示密码输入导航控制器。
    [rootVC.presentedViewController ?: rootVC presentViewController:wrapVC animated:false completion:nil];
    self.presentingPasswdVC = wrapVC;// 更新当前展示的密码输入导航控制器的引用。
}

- (void)onAppBecomeActive {
    NSLog(@"active");
    LogApplicationState;// 记录应用程序当前的状态信息。
    self.isActive = TRUE;// 更新应用程序的活跃状态为真（TRUE）。
    if ([self isBlurEffectPresented]) {// 检查是否有模糊效果视图正在展示。
        [self dismissBlurEffect];// 如果有模糊效果视图正在展示，则解散它。
    }
    [WBEventManager onAppBecomeActive];// 通知事件管理器应用程序已变得活跃，可能触发相关的事件处理
    if (vapp_is_running()) {
        return;
    }
    [WBPaymentManager.sharedManager onAppBecomeActive];// 通知支付管理器应用程序已变得活跃，可能进行支付事务的恢复或其他操作。
}


- (void)onAppResignActive {
    NSLog(@"inactive");
    self.isActive = FALSE;// 更新应用程序的活跃状态为假（FALSE）。
    WBVAppModel *runningVApp = [WBVAppManager sharedManager].runningVApp;// 获取当前正在运行的虚拟应用（VApp）模型。
    if ([WBSettingManager sharedManager].IsVIP && runningVApp != nil && runningVApp.autoLockDuration > 0) {// 检查用户是否为 VIP，并且当前运行的 VApp 是否存在且设置了自动锁定时长。
        // 如果用户是 VIP 并且设置了自动锁定时长，则展示模糊效果，提示用户应用程序即将锁定。
        [self presentBlurEffect];
    }
    // 通知事件管理器应用程序已失去活跃状态，可能触发相关的事件处理。
    [WBEventManager onAppResignActive];
}



