#pragma mark logics

- (void)setRootViewController:(Class)cls {
    _rootvc = cls;// 将传入的类对象赋值给 _rootvc，更新应用程序的根视图控制器的类引用。
    // 异步在主队列上执行以下UI更新操作。
    dispatch_async(dispatch_get_main_queue(), ^{
        UIViewController *vc = nil; // 复用或创建根视图控制器的实例
        if (cls == [WBMainViewController class]) {
            vc = self.mainVCInstance;
        } else if (cls == [WBSubMainViewController class]) {
            vc = self.subMainVCInstance;
        } else {
            vc = [[cls alloc] init];
        }
        [WBAppManager setUIApplicationRootViewController:vc];// 通过类方法设置UIApplication的根视图控制器。
        [WBPopupManager.sharedManager showPopup];// 通知弹出管理器展示弹出视图。
    });
}

- (Class)getRootViewControllerClass{
    return _rootvc;
}

